async function run() {
  await connectDB();
  let done = 0;
  for (const { slug, cz, zh } of localizedNames) {
    const result = await Location.findOneAndUpdate(
      { slug },
      { $set: { 'localizedNames.cz': cz, 'localizedNames.zh': zh } },
      { new: true }
    );
    if (result) { done++; console.log(`Updated: ${slug}`); }
    else console.log(`Not found: ${slug}`);
  }
  console.log(`\nDone. ${done} updated.`);
  process.exit(0);
}

run().catch(err => { console.error(err); process.exit(1); });
